async fn finalize_thread_spawn(&amp;self, codex: Codex, thread_id: ThreadId, ...) -> CodexResult&lt;NewThread> &#123;
    // 步骤①：等待首条事件（SessionConfigured）
    let event = codex.next_event().await?;
    let session_configured = match event &#123;
        Event &#123; id, msg: EventMsg::SessionConfigured(sc) &#125; if id == INITIAL_SUBMIT_ID => sc,
        _ => return Err(CodexErr::SessionConfiguredNotFirstEvent),
    &#125;;

    // 步骤②：原子写入 HashMap（写锁）
    &#123;
        let mut threads = self.threads.write().await;
        if let Entry::Vacant(e) = threads.entry(thread_id) &#123;
            let thread = Arc::new(CodexThread::new(
                codex,
                session_configured.clone(),
                session_configured.rollout_path.clone(),
                session_source,
                watch_registration,
            ));
            e.insert(thread.clone());
            return Ok(NewThread &#123; thread_id, thread, session_configured &#125;);
        &#125;
    &#125;
    // 如果 thread_id 冲突 → 关闭新创建的 Codex，返回错误
&#125;

三个关键设计细节：
① 等待 SessionConfigured 才注册：确保 Thread 在进入注册表时已经完成了所有初始化（技能加载、环境检查）。外部通过 get_thread(id) 拿到的 Thread 一定是”就绪”的。
② Vacant 检查：threads.entry(thread_id) 使用 Entry API，保证”读-检查-插入”三步操作的原子性。如果 thread_id 已被占用（比如两个请求同时尝试创建同一个恢复线程），会走到 shutdown_and_wait 清理冗余实例。
③ 广播通知：finalize 完成后调用 notify_thread_created(thread_id)，通过 broadcast::Sender 推送新 Thread 的 ID。

三、Resume：恢复已有的对话用户关闭应用后重新打开，如何恢复昨天的对话进度？resume_thread_with_history 的处理比”重新 spawn”多了一个关键步骤——去重检查。
